class MyLinkedList:
    def __init__(self):
        self.head = Node()      # sentinel
        self.tail = Node()      # sentinel
        self.head.next = self.tail
        self.tail.prev = self.head
        self.size = 0

    def _node_at(self, index):
        # walk from the nearer end
        if index < self.size - index:
            cur = self.head.next
            for _ in range(index):
                cur = cur.next
        else:
            cur = self.tail.prev
            for _ in range(self.size - 1 - index):
                cur = cur.prev
        return cur

    def get(self, index):
        if index < 0 or index >= self.size:
            return -1
        return self._node_at(index).val

    def _insert_before(self, nxt, val):
        prev = nxt.prev
        node = Node(val)
        node.prev, node.next = prev, nxt
        prev.next = nxt.prev = node
        self.size += 1

    def addAtHead(self, val):
        self._insert_before(self.head.next, val)

    def addAtTail(self, val):
        self._insert_before(self.tail, val)

    def addAtIndex(self, index, val):
        if index < 0 or index > self.size:
            return
        nxt = self.tail if index == self.size else self._node_at(index)
        self._insert_before(nxt, val)

    def deleteAtIndex(self, index):
        if index < 0 or index >= self.size:
            return
        node = self._node_at(index)
        node.prev.next = node.next
        node.next.prev = node.prev
        self.size -= 1

