def num_islands(grid):
    if not grid: return 0
    m,n=len(grid),len(grid[0]); seen=set(); count=0
    def dfs(i,j):
        st=[(i,j)]
        while st:
            x,y=st.pop()
            if 0<=x<m and 0<=y<n and grid[x][y]==1 and (x,y) not in seen:
                seen.add((x,y)); st+=[(x+1,y),(x-1,y),(x,y+1),(x,y-1)]
    for i in range(m):
        for j in range(n):
            if grid[i][j]==1 and (i,j) not in seen: dfs(i,j); count+=1
    return count

def max_area_of_island(grid):
    m,n=len(grid),len(grid[0]); seen=set(); best=0
    def area(i,j):
        st=[(i,j)]; a=0
        while st:
            x,y=st.pop()
            if 0<=x<m and 0<=y<n and grid[x][y]==1 and (x,y) not in seen:
                seen.add((x,y)); a+=1; st+=[(x+1,y),(x-1,y),(x,y+1),(x,y-1)]
        return a
    for i in range(m):
        for j in range(n):
            if grid[i][j]==1 and (i,j) not in seen: best=max(best,area(i,j))
