def flood_fill(image, sr, sc, color):
    m,n=len(image),len(image[0]); old=image[sr][sc]
    if old==color: return image
    st=[(sr,sc)]
    while st:
        x,y=st.pop()
        if 0<=x<m and 0<=y<n and image[x][y]==old:
            image[x][y]=color; st+=[(x+1,y),(x-1,y),(x,y+1),(x,y-1)]
    return image

def can_finish(numCourses, prerequisites):
    from collections import defaultdict, deque
    g=defaultdict(list); indeg=[0]*numCourses
    for a,b in prerequisites: g[b].append(a); indeg[a]+=1
    q=deque(i for i in range(numCourses) if indeg[i]==0); seen=0
    while q:
        n=q.popleft(); seen+=1
        for nxt in g[n]:
            indeg[nxt]-=1
            if indeg[nxt]==0: q.append(nxt)
    return seen==numCourses

