def coin_change_dp(coins, amount):
    INF=float('inf'); dp=[0]+[INF]*amount
    for a in range(1,amount+1):
        for c in coins:
            if c<=a: dp[a]=min(dp[a],dp[a-c]+1)
    return dp[amount] if dp[amount]!=INF else -1

def length_lis(nums):
